import { existsSync, readdirSync, readFileSync, writeFileSync } from "node:fs";
import { basename, dirname, isAbsolute, relative, resolve, sep } from "node:path";
import { fileURLToPath } from "node:url";
import {
	harnessRoot as defaultHarnessRoot,
	isInside,
	pathLabel,
	readToml,
} from "./lib/files.mjs";

const GENERATED_HEADER = `// Generated from harness.toml and its declared component TOML files.
// Do not edit this file directly. Run \`npm run generate:hcp-sources\`.
`;

const IGNORED_SCAN_DIRECTORIES = new Set([
	".git",
	".research",
	"__tests__",
	"dist",
	"node_modules",
	"target",
	"test",
	"tests",
]);
const RESERVED_IDENTIFIERS = new Set([
	"await",
	"break",
	"case",
	"catch",
	"class",
	"const",
	"continue",
	"debugger",
	"default",
	"delete",
	"do",
	"else",
	"enum",
	"export",
	"extends",
	"false",
	"finally",
	"for",
	"function",
	"if",
	"import",
	"in",
	"instanceof",
	"let",
	"new",
	"null",
	"return",
	"static",
	"super",
	"switch",
	"this",
	"throw",
	"true",
	"try",
	"typeof",
	"var",
	"void",
	"while",
	"with",
	"yield",
]);

function invariant(condition, message) {
	if (!condition) throw new Error(message);
}

function normalizedPath(path) {
	return path.split(sep).join("/");
}

function resolveHarnessPath(root, path) {
	const resolved = isAbsolute(path) ? resolve(path) : resolve(root, path);
	invariant(isInside(root, resolved), `Declared path escapes harness root: ${path}`);
	return resolved;
}

function implementationDirectories(root, moduleDir, spec) {
	const directories = [];
	for (const entry of Array.isArray(spec.impl) ? spec.impl : []) {
		if (typeof entry !== "string" || entry.trim() === "") continue;
		const implementationPath = resolveHarnessPath(root, entry);
		if (!isInside(moduleDir, implementationPath)) continue;
		directories.push(dirname(implementationPath));
	}
	return directories;
}

function sourceDirectoriesFromImpl(root, moduleDir, spec, source) {
	const found = new Set();
	for (const start of implementationDirectories(root, moduleDir, spec)) {
		let current = start;
		while (isInside(moduleDir, current)) {
			if (basename(current) === source) found.add(current);
			if (current === moduleDir) break;
			current = dirname(current);
		}
	}
	return [...found];
}

function declaredSourceNames(spec, context, { allowEmpty = false } = {}) {
	const selected = typeof spec.source === "string" && spec.source.trim() !== "" ? spec.source : undefined;
	const explicit = Array.isArray(spec.sources)
		? spec.sources.map((source) => {
			invariant(typeof source === "string" && source.trim() !== "", `${context} has an invalid sources entry`);
			return source;
		})
		: [];
	invariant(new Set(explicit).size === explicit.length, `${context} declares duplicate sources`);
	if (explicit.length > 0 && selected) {
		invariant(explicit.includes(selected), `${context} selected source=${selected} is missing from sources`);
	}
	const sources = explicit.length > 0 ? explicit : selected ? [selected] : [];
	if (!allowEmpty) invariant(sources.length > 0, `${context} is missing a source`);
	return sources;
}

function recursivelyFindSourceDirectories(moduleDir, source) {
	const found = [];
	const visit = (directory) => {
		for (const entry of readdirSync(directory, { withFileTypes: true })) {
			if (!entry.isDirectory() || IGNORED_SCAN_DIRECTORIES.has(entry.name)) continue;
			const child = resolve(directory, entry.name);
			if (entry.name === source) found.push(child);
			visit(child);
		}
	};
	visit(moduleDir);
	return found;
}

/**
 * Resolve a descriptor's declared source directory without assuming it is a
 * direct child of the module. The `impl` entries are authoritative when they
 * identify a nested source such as `multiagent/workflow/magenta`.
 */
export function findModuleSourceDirectories(root, moduleDir, spec, source) {
	if (!source) return [];
	const fromImpl = sourceDirectoriesFromImpl(root, moduleDir, spec, source);
	if (fromImpl.length > 0) return fromImpl.sort();

	const direct = resolve(moduleDir, source);
	if (existsSync(direct)) return [direct];
	return recursivelyFindSourceDirectories(moduleDir, source).sort();
}

export function findComponentSourceDirectories(root, componentPath, spec, source = spec.source) {
	return findModuleSourceDirectories(root, dirname(componentPath), spec, source);
}

/** Resolve exactly one source-owned HcpMagnet.ts for a declared component. */
export function HcpClientfindcomponentmagnet(root, componentPath, spec, source = spec.source) {
	invariant(typeof source === "string" && source !== "", `${pathLabel(componentPath, root)} is missing a source`);
	const candidates = findComponentSourceDirectories(root, componentPath, spec, source)
		.map((directory) => resolve(directory, "HcpMagnet.ts"))
		.filter((path) => existsSync(path));
	const unique = [...new Set(candidates)].sort();
	invariant(
		unique.length > 0,
		`Cannot find HcpMagnet.ts for ${pathLabel(componentPath, root)} source=${source}. ` +
			"Declare impl paths that pass through the source directory or add <source>/HcpMagnet.ts.",
	);
	invariant(
		unique.length === 1,
		`Ambiguous HcpMagnet.ts for ${pathLabel(componentPath, root)} source=${source}: ` +
			unique.map((path) => pathLabel(path, root)).join(", "),
	);
	return unique[0];
}

function assertNamedClassExport(path, className, root) {
	const source = readFileSync(path, "utf8");
	invariant(
		new RegExp(`\\bexport\\s+class\\s+${className}\\b`).test(source),
		`${pathLabel(path, root)} must export class ${className}`,
	);
}

function assertStaticBuild(path, root) {
	const source = readFileSync(path, "utf8");
	invariant(
		/\bstatic\s+(?:async\s+)?build\s*\(/.test(source),
		`${pathLabel(path, root)} must expose static build(context); every HcpMagnet uses one construction path`,
	);
}

const HCP_PRODUCTS = new Set(["tool", "capability", "resource"]);

function stringField(spec, field, context, { required = false } = {}) {
	const value = spec[field];
	if (value === undefined && !required) return undefined;
	invariant(typeof value === "string" && value.trim() !== "", `${context} is missing ${field}`);
	return value;
}

function booleanField(spec, field, context) {
	const value = spec[field];
	if (value === undefined) return false;
	invariant(typeof value === "boolean", `${context} has invalid ${field}; expected a boolean`);
	return value;
}

function stringArrayField(spec, field, context) {
	const value = spec[field];
	if (value === undefined) return [];
	invariant(Array.isArray(value), `${context} has invalid ${field}; expected an array`);
	for (const item of value) {
		invariant(typeof item === "string" && item.trim() !== "", `${context} has an invalid ${field} entry`);
	}
	invariant(new Set(value).size === value.length, `${context} declares duplicate ${field} entries`);
	return value;
}

function componentMetadata(spec, context, { productRequired = true } = {}) {
	const product = stringField(spec, "product", context, { required: productRequired });
	if (product !== undefined) {
		invariant(HCP_PRODUCTS.has(product), `${context} has invalid product=${product}`);
	}
	const slot = stringField(spec, "slot", context);
	if (product === "capability") {
		invariant(slot !== undefined, `${context} product=capability is missing slot`);
	} else {
		invariant(slot === undefined, `${context} product=${product ?? "<missing>"} cannot declare slot`);
	}
	return {
		product,
		slot,
		autoload: booleanField(spec, "autoload", context),
		hotSwappable: booleanField(spec, "hot_swappable", context),
		requires: stringArrayField(spec, "requires", context),
	};
}

function componentMetadataForSource(spec, source, metadata, context) {
	const sourceConfigs = spec.source_config;
	if (sourceConfigs === undefined) return metadata;
	invariant(
		sourceConfigs && typeof sourceConfigs === "object" && !Array.isArray(sourceConfigs),
		`${context} has invalid source_config; expected a table`,
	);
	const config = sourceConfigs[source];
	if (config === undefined) return metadata;
	invariant(
		config && typeof config === "object" && !Array.isArray(config),
		`${context} has invalid source_config.${source}; expected a table`,
	);
	return {
		...metadata,
		autoload: config.autoload === undefined ? metadata.autoload : booleanField(config, "autoload", context),
		hotSwappable:
			config.hot_swappable === undefined
				? metadata.hotSwappable
				: booleanField(config, "hot_swappable", context),
		requires: [...new Set([...metadata.requires, ...stringArrayField(config, "requires", context)])],
	};
}

function assertStringMetadata(path, property, expected, root, { isStatic = false } = {}) {
	const source = readFileSync(path, "utf8");
	const prefix = isStatic ? "static\\s+" : "";
	const match = source.match(
		new RegExp(`\\b${prefix}readonly\\s+${property}(?:\\s*:\\s*[^=;]+)?\\s*=\\s*["']([^"']+)["']`),
	);
	invariant(match, `${pathLabel(path, root)} must declare ${isStatic ? "static " : ""}readonly ${property}`);
	invariant(
		match[1] === expected,
		`${pathLabel(path, root)} ${property}=${match[1]} does not match TOML declaration ${expected}`,
	);
}

function recursivelyFindRoleFiles(root, roleFile) {
	const found = [];
	const visit = (directory) => {
		for (const entry of readdirSync(directory, { withFileTypes: true })) {
			if (entry.isDirectory()) {
				if (!IGNORED_SCAN_DIRECTORIES.has(entry.name)) visit(resolve(directory, entry.name));
				continue;
			}
			if (entry.isFile() && entry.name === roleFile) found.push(resolve(directory, entry.name));
		}
	};
	visit(root);
	return found.sort();
}

function assertAllRoleFilesDeclared(root, servers, magnets) {
	const declaredServerPaths = new Set(servers.map(({ path }) => path));
	const declaredMagnetPaths = new Set(magnets.map(({ path }) => path));
	const undeclaredServers = recursivelyFindRoleFiles(root, "HcpServer.ts").filter(
		(path) => !declaredServerPaths.has(path),
	);
	const undeclaredMagnets = recursivelyFindRoleFiles(root, "HcpMagnet.ts").filter(
		(path) => !declaredMagnetPaths.has(path),
	);
	invariant(
		undeclaredServers.length === 0,
		`HcpServer.ts role files missing from TOML declarations: ${undeclaredServers.map((path) => pathLabel(path, root)).join(", ")}`,
	);
	invariant(
		undeclaredMagnets.length === 0,
		`HcpMagnet.ts role files missing from TOML declarations: ${undeclaredMagnets.map((path) => pathLabel(path, root)).join(", ")}`,
	);
}

function selectedComponentLabel(entry) {
	return entry.slot ?? `${entry.kind}:${entry.name}`;
}

function assertSelectedComponentDependencies(entries) {
	const selectedEntries = entries.filter(({ selected }) => selected);
	const providersByTarget = new Map();
	for (const entry of selectedEntries.filter(({ product }) => product === "capability")) {
		invariant(entry.slot, `${entry.descriptorPath} selected capability has no slot`);
		invariant(
			!providersByTarget.has(entry.slot),
			`${entry.descriptorPath} duplicates selected capability slot ${entry.slot}`,
		);
		providersByTarget.set(entry.slot, entry);
	}

	for (const entry of selectedEntries) {
		for (const requirement of entry.requires) {
			invariant(
				providersByTarget.has(requirement),
				`${entry.descriptorPath} requires ${requirement}, but no selected component provides that target`,
			);
		}
	}

	const state = new Map();
	const stack = [];
	const visit = (entry) => {
		state.set(entry, "visiting");
		stack.push(entry);
		for (const dependency of new Set(entry.requires.map((requirement) => providersByTarget.get(requirement)))) {
			if (state.get(dependency) === "visiting") {
				const cycleStart = stack.indexOf(dependency);
				const cycle = [...stack.slice(cycleStart), dependency].map(selectedComponentLabel);
				invariant(false, `Selected component dependency cycle: ${cycle.join(" -> ")}`);
			}
			if (state.get(dependency) !== "visited") visit(dependency);
		}
		stack.pop();
		state.set(entry, "visited");
	};

	for (const entry of selectedEntries) {
		if (state.has(entry)) continue;
		visit(entry);
	}
}

/**
 * Collect assembly imports from the TOML declarations. Every component row is a
 * real Harness Module and therefore must own an HcpServer and source HcpMagnet.
 * Generated role imports are deduplicated, while component rows retain every
 * component/source pairing. A shared role class can therefore serve multiple slots.
 */
export function HcpClientcollectsources(options = {}) {
	const root = resolve(options.harnessRoot ?? defaultHarnessRoot);
	const harnessTomlPath = resolve(options.harnessTomlPath ?? resolve(root, "harness.toml"));
	invariant(existsSync(harnessTomlPath), `Missing harness.toml index: ${pathLabel(harnessTomlPath, root)}`);
	const harnessIndex = readToml(harnessTomlPath);
	const modules = Array.isArray(harnessIndex.modules) ? harnessIndex.modules : [];
	const components = Array.isArray(harnessIndex.components) ? harnessIndex.components : [];
	const serversByPath = new Map();
	const magnetsByPath = new Map();
	const entries = [];

	const collectServer = (moduleDir, context) => {
		const serverPath = resolve(moduleDir, "HcpServer.ts");
		invariant(
			existsSync(serverPath),
			`${context} is missing ${pathLabel(serverPath, root)}. Infrastructure and shared libraries must not be ` +
				"declared as Harness Modules; real Modules require HcpServer.ts.",
		);
		const module = normalizedPath(relative(root, moduleDir));
		invariant(module !== "" && module !== ".", `${context} has no module directory`);
		assertNamedClassExport(serverPath, "HcpServer", root);
		assertStringMetadata(serverPath, "moduleName", module, root);
		const existingServer = serversByPath.get(serverPath);
		invariant(!existingServer || existingServer.module === module, `Conflicting module keys for ${pathLabel(serverPath, root)}`);
		serversByPath.set(serverPath, { module, path: serverPath });
		return module;
	};

	const collectMagnetEntry = ({ moduleDir, spec, source, kind, name, descriptorPath, context, metadata }) => {
		const effectiveMetadata = componentMetadataForSource(spec, source, metadata, context);
		const candidates = findModuleSourceDirectories(root, moduleDir, spec, source)
			.map((directory) => resolve(directory, "HcpMagnet.ts"))
			.filter((path) => existsSync(path));
		const unique = [...new Set(candidates)].sort();
		invariant(
			unique.length > 0,
			`Cannot find HcpMagnet.ts for ${context} source=${source}. ` +
				"Declare impl paths that pass through the source directory or add <source>/HcpMagnet.ts.",
		);
		invariant(
			unique.length === 1,
			`Ambiguous HcpMagnet.ts for ${context} source=${source}: ` +
				unique.map((path) => pathLabel(path, root)).join(", "),
		);
		const magnetPath = unique[0];
		const module = normalizedPath(relative(root, moduleDir));
		assertNamedClassExport(magnetPath, "HcpMagnet", root);
		assertStaticBuild(magnetPath, root);
		assertStringMetadata(magnetPath, "module", module, root, { isStatic: true });
		assertStringMetadata(magnetPath, "kind", kind, root, { isStatic: true });
		assertStringMetadata(magnetPath, "source", source, root, { isStatic: true });
		const existingMagnet = magnetsByPath.get(magnetPath);
		invariant(
			!existingMagnet ||
				(existingMagnet.module === module && existingMagnet.source === source && existingMagnet.kind === kind),
			`Conflicting source metadata for ${pathLabel(magnetPath, root)}`,
		);
		magnetsByPath.set(magnetPath, { kind, module, source, path: magnetPath });
		entries.push({
			module,
			kind,
			name,
			product: effectiveMetadata.product,
			source,
			selected: spec.source === source,
			autoload: effectiveMetadata.autoload,
			hotSwappable: effectiveMetadata.hotSwappable,
			descriptorPath: normalizedPath(relative(root, descriptorPath)),
			...(effectiveMetadata.slot === undefined ? {} : { slot: effectiveMetadata.slot }),
			requires: effectiveMetadata.requires,
			path: magnetPath,
		});
	};

	for (const entry of modules) {
		if (!entry || typeof entry !== "object" || Array.isArray(entry)) continue;
		invariant(
			typeof entry.path === "string" && entry.path.trim() !== "",
			`harness.toml module row ${entry.kind ?? "<unknown>"}:${entry.name ?? "<unknown>"} has no path`,
		);
		invariant(
			typeof entry.kind === "string" && entry.kind.trim() !== "",
			`harness.toml module row ${entry.name ?? "<unknown>"} has no kind`,
		);
		const moduleDir = resolveHarnessPath(root, entry.path);
		invariant(existsSync(moduleDir), `Missing module directory: ${pathLabel(moduleDir, root)}`);
		const context = `Declared Harness Module ${entry.kind}:${entry.name}`;
		collectServer(moduleDir, context);
		const sources = declaredSourceNames(entry, context, { allowEmpty: true });
		const metadata = componentMetadata(entry, context, { productRequired: sources.length > 0 });
		for (const source of sources) {
			collectMagnetEntry({
				moduleDir,
				spec: entry,
				source,
				kind: entry.kind,
				name: stringField(entry, "name", context, { required: true }),
				descriptorPath: harnessTomlPath,
				context,
				metadata,
			});
		}
	}

	for (const component of components) {
		if (!component || typeof component !== "object" || Array.isArray(component)) continue;
		invariant(
			typeof component.path === "string" && component.path.trim() !== "",
			`harness.toml component row ${component.kind ?? "<unknown>"}:${component.name ?? "<unknown>"} has no path`,
		);
		const componentPath = resolveHarnessPath(root, component.path);
		invariant(existsSync(componentPath), `Missing component TOML: ${pathLabel(componentPath, root)}`);
		const spec = readToml(componentPath);
		const moduleDir = dirname(componentPath);
		invariant(
			typeof spec.kind === "string" && spec.kind.trim() !== "",
			`${pathLabel(componentPath, root)} is missing kind`,
		);
		invariant(
			spec.kind === component.kind,
			`${pathLabel(componentPath, root)} kind=${spec.kind} does not match harness.toml declaration kind=${component.kind}`,
		);
		const context = `Declared Harness Module ${component.kind ?? "<unknown>"}:${component.name ?? "<unknown>"}`;
		collectServer(moduleDir, context);
		const descriptorContext = pathLabel(componentPath, root);
		const metadata = componentMetadata(spec, descriptorContext);
		const name = stringField(spec, "name", descriptorContext, { required: true });
		invariant(
			name === component.name,
			`${descriptorContext} name=${name} does not match harness.toml declaration name=${component.name}`,
		);
		for (const source of declaredSourceNames(spec, pathLabel(componentPath, root))) {
			collectMagnetEntry({
				moduleDir,
				spec,
				source,
				kind: spec.kind,
				name,
				descriptorPath: componentPath,
				context: descriptorContext,
				metadata,
			});
		}
	}

	const servers = [...serversByPath.values()].sort((left, right) => left.module.localeCompare(right.module));
	const magnets = [...magnetsByPath.values()].sort((left, right) =>
		normalizedPath(relative(root, left.path)).localeCompare(normalizedPath(relative(root, right.path))),
	);
	entries.sort((left, right) => {
		const descriptorOrder = left.descriptorPath.localeCompare(right.descriptorPath);
		return descriptorOrder !== 0 ? descriptorOrder : left.source.localeCompare(right.source);
	});
	assertSelectedComponentDependencies(entries);
	assertAllRoleFilesDeclared(root, servers, magnets);

	return {
		harnessRoot: root,
		harnessTomlPath,
		servers,
		magnets,
		entries,
	};
}

function namespaceIdentifier(root, path) {
	const withoutRoleFile = normalizedPath(relative(root, dirname(path)));
	const words = withoutRoleFile.split(/[^A-Za-z0-9]+/).filter(Boolean);
	invariant(words.length > 0, `Cannot derive namespace import for ${pathLabel(path, root)}`);
	let identifier = words
		.map((word, index) => {
			const normalized = word.replace(/^[^A-Za-z_$]+/, "");
			if (!normalized) return "";
			return index === 0
				? normalized[0].toLowerCase() + normalized.slice(1)
				: normalized[0].toUpperCase() + normalized.slice(1);
		})
		.join("");
	if (!/^[A-Za-z_$]/.test(identifier) || RESERVED_IDENTIFIERS.has(identifier)) identifier = `_${identifier}`;
	return identifier;
}

function importSpecifier(fromDirectory, target) {
	const path = normalizedPath(relative(fromDirectory, target));
	return path.startsWith(".") ? path : `./${path}`;
}

export function HcpClientrendersources(collected, outputPath) {
	const outputDirectory = dirname(outputPath);
	const imports = [];
	const pathsByAlias = new Map();
	const aliasesByPath = new Map();
	for (const entry of [...collected.servers, ...collected.magnets]) {
		const alias = namespaceIdentifier(collected.harnessRoot, entry.path);
		const collision = pathsByAlias.get(alias);
		if (collision && collision !== entry.path) {
			throw new Error(
				`Namespace import ${alias} is ambiguous: ${pathLabel(collision, collected.harnessRoot)} and ` +
					pathLabel(entry.path, collected.harnessRoot),
			);
		}
		pathsByAlias.set(alias, entry.path);
		aliasesByPath.set(entry.path, alias);
		imports.push({ alias, path: entry.path });
	}

	const uniqueImports = [...new Map(imports.map((entry) => [entry.path, entry])).values()].sort((left, right) =>
		left.path.localeCompare(right.path),
	);
	const lines = [GENERATED_HEADER.trimEnd(), ""];
	for (const entry of uniqueImports) {
		lines.push(`import * as ${entry.alias} from "${importSpecifier(outputDirectory, entry.path)}";`);
	}
	lines.push('import type { HcpMagnetBuildContext } from "../HcpMagnetTypes.ts";');
	lines.push(
		"",
		"type HcpServerclass = new () => { readonly moduleName: string; readonly description?: string };",
		"type HcpMagnetclass = {",
		"\treadonly module: string;",
		"\treadonly kind: string;",
		"\treadonly source: string;",
		"\treadonly build: (context: HcpMagnetBuildContext) => unknown | Promise<unknown>;",
		"};",
		"type HcpMagnetentry = {",
		"\treadonly module: string;",
		"\treadonly kind: string;",
		"\treadonly name: string;",
		'\treadonly product: "tool" | "capability" | "resource";',
		"\treadonly source: string;",
		"\treadonly selected: boolean;",
		"\treadonly autoload: boolean;",
		"\treadonly hotSwappable: boolean;",
		"\treadonly descriptorPath: string;",
		"\treadonly slot?: string;",
		"\treadonly requires: readonly string[];",
		"\treadonly HcpMagnet: HcpMagnetclass;",
		"};",
		"",
		"export const HCP_SERVERS: ReadonlyMap<string, HcpServerclass> = new Map<string, HcpServerclass>([",
	);
	for (const server of collected.servers) {
		lines.push(`\t[${JSON.stringify(server.module)}, ${aliasesByPath.get(server.path)}.HcpServer],`);
	}
	lines.push("]);", "", "export const HCP_MAGNETS: readonly HcpMagnetentry[] = [");
	for (const entry of collected.entries) {
		lines.push("\t{");
		for (const field of ["module", "kind", "name", "product", "source"]) {
			lines.push(`\t\t${field}: ${JSON.stringify(entry[field])},`);
		}
		lines.push(
			`\t\tselected: ${entry.selected},`,
			`\t\tautoload: ${entry.autoload},`,
			`\t\thotSwappable: ${entry.hotSwappable},`,
		);
		lines.push(`\t\tdescriptorPath: ${JSON.stringify(entry.descriptorPath)},`);
		if (entry.slot !== undefined) lines.push(`\t\tslot: ${JSON.stringify(entry.slot)},`);
		lines.push(`\t\trequires: ${JSON.stringify(entry.requires).replaceAll(",", ", ")},`);
		lines.push(`\t\tHcpMagnet: ${aliasesByPath.get(entry.path)}.HcpMagnet,`, "\t},");
	}
	lines.push("];", "");
	return lines.join("\n");
}

export function HcpClientgeneratesources(options = {}) {
	const collected = HcpClientcollectsources(options);
	const outputPath = resolve(
		options.outputPath ?? resolve(collected.harnessRoot, ".HCP", "assembly", "sources.generated.ts"),
	);
	const expected = HcpClientrendersources(collected, outputPath);
	const actual = existsSync(outputPath) ? readFileSync(outputPath, "utf8") : undefined;
	if (options.check) {
		invariant(
			actual === expected,
			`${pathLabel(outputPath, collected.harnessRoot)} is missing or stale. Run npm run generate:hcp-sources.`,
		);
		return { changed: false, outputPath, collected };
	}
	const changed = actual !== expected;
	if (changed) writeFileSync(outputPath, expected, "utf8");
	return { changed, outputPath, collected };
}

if (process.argv[1] && resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
	try {
		const unknown = process.argv.slice(2).filter((argument) => argument !== "--check");
		invariant(unknown.length === 0, `Unknown arguments: ${unknown.join(", ")}`);
		const result = HcpClientgeneratesources({ check: process.argv.includes("--check") });
		console.log(
			`${result.changed ? "Generated" : "Checked"} ${pathLabel(result.outputPath, result.collected.harnessRoot)} ` +
				`(${result.collected.servers.length} servers, ${result.collected.magnets.length} unique magnet role files, ` +
				`${result.collected.entries.length} component rows).`,
		);
	} catch (error) {
		console.error(error instanceof Error ? error.message : String(error));
		process.exitCode = 1;
	}
}
